<template>
  <div>
    <a-row :gutter="[16, 16]">
      <a-col :xs="24" :sm="24" :md="24" :lg="12" :xl="12" :xxl="12">
        <div style="width: 100%; background-color: white; padding: 24px">
          <span style="font-size: 18px; color: #1890ff;">评委白名单</span>
          <span style="font-size: 18px; color: gray; float: right;" @click="() => form.list = ''">清除内容</span>
          <a-textarea placeholder="输入评委姓名，一行代表一个评委" v-model="form.list" :rows="8" style="resize: none; margin: 8px 0; font-size: 18px;" />
          <a-button type="primary" style="width: 100%; height: 40px; margin-top: 16px; font-size: 24px;" @click="submit">
            提交
          </a-button>
        </div>
      </a-col>
      <a-col :xs="24" :sm="24" :md="24" :lg="12" :xl="12" :xxl="12">
        <div style="width: 100%; background-color: white; padding: 20px 20px 10px;" v-if="!loading">
          <div style="height: 30px; border-bottom: 1px solid #ddd;">
            <a-radio-group v-model="filterStatus" size="small" button-style="solid">
              <a-radio-button :value="false">
                全部
              </a-radio-button>
              <a-radio-button :value="true">
                未注册
              </a-radio-button>
            </a-radio-group>
            <span style="font-size: 16px; float: right; color: #aaa;" @click="deleteAll">清空白名单（{{ data.length }}）</span>
          </div>
          <a-list item-layout="horizontal" :data-source="data">
            <a-list-item slot="renderItem" slot-scope="item" v-show="!filterStatus || (filterStatus && !item.status)">
              <a slot="actions" style="color: red; font-size: 20px;" @click="deleteItem(item)">删除</a>
              <a-list-item-meta description="">
                <span slot="title" style="font-size: 20px">
                  {{ item.judgeName }}<br v-if="item.status"/>
                  <a-tag v-if="item.status" color="green">
                    已注册
                  </a-tag>
                </span>
              </a-list-item-meta>
            </a-list-item>
          </a-list>
        </div>
        <div style="height:30px; text-align: center; background-color: #fff; border-radius: 4px; margin-bottom: 20px; padding: 30px 50px; margin: 20px 0;" v-else>
          <a-spin />
        </div>
      </a-col>
    </a-row>
  </div>
</template>
<script>
import { judgeWhiteList, removeByName, addJudgeWhiteList, clearAllJudgeWhiteList } from '@/api/judgeWhiteList'
export default {
  data() {
    return {
      filterStatus: false,
      form: {
        list: '',
      },
      data: [],
      loading: false,
    }
  },
  mounted() {
    this.loadData()
  },
  methods: {
    loadData() {
      this.loading = true
      judgeWhiteList(this.$route.params.id).then(res => {
        this.data = res.records
      }).finally(() => { this.loading = false })
    },
    submit() {
      if (this.form.list !== '') {
        addJudgeWhiteList(this.$route.params.id, this.form.list.split('\n')).then(res => {
          this.$message.success('已添加')
          this.form.list = ''
          this.loadData()
        })
      }
    },
    deleteItem(item) {
      const beforeClose = (action, done) => {
        if (action === 'confirm') {
          removeByName(item.voteId, item.judgeName).then(() => {
            this.$message.success('已删除')
            this.loadData()
            done()
          })
        } else {
          done()
        }
      }
      this.$dialog.confirm({
        title: '是否删除？',
        confirmButtonText: '是',
        cancelButtonText: '否',
        beforeClose,
      }).catch(() => {})
    },
    deleteAll() {
      if (this.data.length > 0) {
        const beforeClose = (action, done) => {
          if (action === 'confirm') {
            clearAllJudgeWhiteList(this.$route.params.id).then(() => {
              this.$message.success('已删除')
              this.loadData()
              done()
            })
          } else {
            done()
          }
        }
        this.$dialog.confirm({
          title: '是否删除全部？',
          confirmButtonText: '是',
          cancelButtonText: '否',
          beforeClose,
        }).catch(() => {})
      }
    },
  },
}
</script>
<style scoped lang="less">
::v-deep .ant-list-item-meta-title {
  margin: 0px !important;
}
</style>
