import request from '@/utils/request'

export function judgeWhiteList(voteId) {
  return request({
    url: `/judgeWhitelist/selectAllJudgeWhitelistByVoteId?voteId=${voteId}&page=1&size=500`,
    method: 'get',
  })
}

export function addJudgeWhiteList(voteId, data) {
  return request({
    url: `/judgeWhitelist/addList?voteId=${voteId}`,
    method: 'post',
    data: data,
  })
}

export function clearAllJudgeWhiteList(voteId) {
  return request({
    url: `/judgeWhitelist/clearAllByVoteId?voteId=${voteId}`,
    method: 'post',
  })
}

export function removeByName(voteId, judgeName) {
  return request({
    url: `/judgeWhitelist/removeByName?voteId=${voteId}&judgeName=${judgeName}`,
    method: 'post',
  })
}

export function resetWhitelistJudge(voteId, judgeName) {
  return request({
    url: `/judgeWhitelist/resetWhitelistJudge?voteId=${voteId}&judgeName=${judgeName}`,
    method: 'post',
  })
}
